class Solution:
    def beautifulIndices(self, s, a, b, k):
        import bisect
        def find_all(text, pat):
            res = []
            start = 0
            while True:
                idx = text.find(pat, start)
                if idx == -1:
                    break
                res.append(idx)
                start = idx + 1
            return res
        a_idxs = find_all(s, a)
        b_idxs = find_all(s, b)
        result = []
        for i in a_idxs:
            pos = bisect.bisect_left(b_idxs, i)
            found = False
            for p in [pos - 1, pos]:
                if 0 <= p < len(b_idxs) and abs(b_idxs[p] - i) <= k:
                    found = True
                    break
            if found:
                result.append(i)
        return result

