var beautifulIndices = function(s, a, b, k) {
    function findAll(text, pat) {
        const res = [];
        let start = 0;
        while (true) {
            const idx = text.indexOf(pat, start);
            if (idx === -1) break;
            res.push(idx);
            start = idx + 1;
        }
        return res;
    }
    function bisectLeft(arr, val) {
        let lo = 0, hi = arr.length;
        while (lo < hi) { const mid = (lo+hi)>>1; if (arr[mid] < val) lo=mid+1; else hi=mid; }
        return lo;
    }
    const aIdxs = findAll(s, a);
    const bIdxs = findAll(s, b);
    const result = [];
    for (const i of aIdxs) {
        const pos = bisectLeft(bIdxs, i);
        let found = false;
        for (const p of [pos-1, pos]) {
            if (p >= 0 && p < bIdxs.length && Math.abs(bIdxs[p] - i) <= k) {
                found = true; break;
            }
        }
        if (found) result.push(i);
    }
    return result;
};
